import type { Metadata } from "next";
import Tracking from "./Tracking";

export const metadata: Metadata = {
  title: "配送追跡 / 運行管理 | ぐんじょう WMS",
  description:
    "配送追跡・運行管理（在庫出荷後の配送中モニタリング工程）の画面。配送センターのオペレーターが日中に稼働中の便を監視するボード。運行サマリ（配送日 / 配送センター）と KPI（稼働便数 / 配送中 / 完了 / 遅延便数 / 不在件数 / 全体進捗）を表示。便（run）一覧から便を選ぶと、その便の配送ストップを順番に並べた縦型ルートタイムラインを表示。各ストップは 順番 / お届け先（氏名・住所）/ 個数 / 到着予定（planned ETA）/ 実績（actual arrival）/ ステータス（未配 / 配送中・現在地 / 完了 / 不在 / 遅延）を持ち、ドライバーの現在地ストップが視覚的に区別される（完了は上、未配は下）。遅延（ETA のずれ）や不在を検知して、遅延理由（交通渋滞 / 長時間荷下ろし / 不在）の確認、再配達日時の設定、お客様への連絡といった例外処理を行うモニタリングボード。",
};

export default function TrackingPage() {
  return <Tracking />;
}

// 配送追跡 / 運行管理 — data model + tracking logic (pure, testable, no React).

export type StopStatus = "pending" | "enroute" | "done" | "absent" | "late";
export type RunStatus = "waiting" | "delivering" | "delayed" | "done";

export interface DeliveryStop {
  /** 1-based order along the route. */
  seq: number;
  /** お届け先 氏名 */
  customer: string;
  /** お届け先 住所 */
  address: string;
  /** 個数 */
  parcels: number;
  /** Planned ETA, "HH:MM" (24h). */
  plannedEta: string;
  /** Actual arrival "HH:MM" once the driver has reached/handled the stop. */
  actualAt?: string;
  status: StopStatus;
  /** 不在 → 再配達 reschedule (set when handled). */
  rescheduledTo?: string;
  /** Free note (不在票投函 / 置き配 etc.). */
  note?: string;
}

export interface DelayInfo {
  reason: "traffic" | "unloading" | "absent" | "other";
  minutes: number;
}

export interface Run {
  id: string;
  /** 便名 / ルート, e.g. "1便 — 中央エリア". */
  name: string;
  route: string;
  driver: string;
  vehicle: string;
  /** 待機 has no current position yet. */
  status: RunStatus;
  delay?: DelayInfo;
  stops: DeliveryStop[];
}

export interface CenterMeta {
  date: string;
  center: string;
}

/* ───────────────────────── tracking logic ───────────────────────── */

/** "HH:MM" → minutes since midnight. */
export function toMinutes(hhmm: string): number {
  const [h, m] = hhmm.split(":").map(Number);
  return h * 60 + m;
}

/** minutes since midnight → "HH:MM". */
export function fromMinutes(min: number): string {
  const m = ((min % (24 * 60)) + 24 * 60) % (24 * 60);
  return `${String(Math.floor(m / 60)).padStart(2, "0")}:${String(m % 60).padStart(2, "0")}`;
}

/** A stop counts as finished (no longer blocking the driver) when 完了. */
export function isStopDone(s: DeliveryStop): boolean {
  return s.status === "done";
}

/** 不在 blocks "run complete" until a 再配達 is scheduled. */
export function isStopBlocking(s: DeliveryStop): boolean {
  return s.status === "absent" && !s.rescheduledTo;
}

/** Completed stops / total stops. */
export function runProgress(run: Run): { done: number; total: number; pct: number } {
  const total = run.stops.length;
  const done = run.stops.filter(isStopDone).length;
  return { done, total, pct: total === 0 ? 0 : Math.round((done / total) * 100) };
}

/**
 * The current stop = the first stop that is not yet finished. `enroute` wins if
 * present (driver explicitly here); otherwise the first non-done stop.
 */
export function currentStopSeq(run: Run): number | null {
  const enroute = run.stops.find((s) => s.status === "enroute");
  if (enroute) return enroute.seq;
  const next = run.stops.find((s) => !isStopDone(s));
  return next ? next.seq : null;
}

/** Delay in minutes for a stop = (actual ?? now-projected) − planned. Positive = late. */
export function stopDelayMin(s: DeliveryStop): number | null {
  if (s.actualAt) return toMinutes(s.actualAt) - toMinutes(s.plannedEta);
  return null;
}

/** A stop is running late when its actual beat its planned by > threshold, or flagged late. */
export function isStopLate(s: DeliveryStop, thresholdMin = 5): boolean {
  if (s.status === "late") return true;
  const d = stopDelayMin(s);
  return d !== null && d > thresholdMin;
}

/** Next planned arrival among remaining (non-done) stops, "HH:MM" or null. */
export function nextEta(run: Run): string | null {
  const seq = currentStopSeq(run);
  if (seq === null) return null;
  const stop = run.stops.find((s) => s.seq === seq);
  return stop ? stop.plannedEta : null;
}

/** A run is complete only when every stop is 完了 (no 不在 left unrescheduled). */
export function isRunComplete(run: Run): boolean {
  return run.stops.length > 0 && run.stops.every(isStopDone);
}

/** Any 不在 stop still needing a 再配達. */
export function hasUnresolvedAbsent(run: Run): boolean {
  return run.stops.some(isStopBlocking);
}

export interface BoardKpis {
  activeRuns: number; // 稼働便数 (待機含む稼働中の便)
  delivering: number; // 配送中の便
  doneRuns: number; // 完了便
  delayedRuns: number; // 遅延便数
  absentStops: number; // 不在件数 (未処理)
  doneStops: number; // 完了 stops
  totalStops: number; // 総 stops
  progressPct: number; // 全体進捗
}

export function computeKpis(runs: Run[]): BoardKpis {
  let doneStops = 0;
  let totalStops = 0;
  let absentStops = 0;
  let activeRuns = 0;
  let delivering = 0;
  let doneRuns = 0;
  let delayedRuns = 0;

  for (const run of runs) {
    const p = runProgress(run);
    doneStops += p.done;
    totalStops += p.total;
    absentStops += run.stops.filter(isStopBlocking).length;

    if (run.status === "done" || isRunComplete(run)) doneRuns += 1;
    else activeRuns += 1; // 待機 + 配送中 + 遅延 are all "稼働"
    if (run.status === "delivering") delivering += 1;
    if (run.status === "delayed") delayedRuns += 1;
  }

  return {
    activeRuns,
    delivering,
    doneRuns,
    delayedRuns,
    absentStops,
    doneStops,
    totalStops,
    progressPct: totalStops === 0 ? 0 : Math.round((doneStops / totalStops) * 100),
  };
}

