/* ───────────────────────── helpers ───────────────────────── */

/** Signed early/late minutes display for a finished stop. */
function StopDelta({ stop }: { stop: DeliveryStop }) {
  const d = stopDelayMin(stop);
  if (d === null) return null;
  return (
    <Delta
      value={d}
      format={(v) => `${Math.abs(v)}分`}
      hideArrow={d === 0}
      showLabel
      tones={{ positive: "destructive", negative: "success", zero: "muted" }}
      labels={{ positive: "遅れ", negative: "早着", zero: "定刻" }}
      className="text-xs"
    />
  );
}

let mutationSeq = 0;

/* ───────────────────────── component ───────────────────────── */

type BoardFilter = "all" | "delivering" | "delayed" | "done";

export default function Tracking() {
  const [runs, setRuns] = React.useState<Run[]>(() => seedRuns());
  const [selectedId, setSelectedId] = React.useState<string>("RUN-1");
  const [filter, setFilter] = React.useState<BoardFilter>("all");
  const [announce, setAnnounce] = React.useState<string>("");

  // Reschedule (再配達) sheet state.
  const [rescheduleStop, setRescheduleStop] = React.useState<{ runId: string; seq: number } | null>(
    null
  );
  const [rescheduleSlot, setRescheduleSlot] = React.useState<string>(REDELIVERY_SLOTS[0].value);

  // Delay-contact sheet state.
  const [detailRunId, setDetailRunId] = React.useState<string | null>(null);

  const kpis = React.useMemo(() => computeKpis(runs), [runs]);

  const selectedRun = runs.find((r) => r.id === selectedId) ?? runs[0] ?? null;

  const filteredRuns = React.useMemo(() => {
    if (filter === "all") return runs;
    if (filter === "done") return runs.filter((r) => r.status === "done" || isRunComplete(r));
    if (filter === "delivering") return runs.filter((r) => r.status === "delivering");
    return runs.filter((r) => r.status === "delayed");
  }, [runs, filter]);

  /* ── mutations ── */

  function updateStop(
    runId: string,
    seq: number,
    patch: Partial<DeliveryStop>,
    recompute = true
  ) {
    setRuns((prev) =>
      prev.map((run) => {
        if (run.id !== runId) return run;
        const stops = run.stops.map((s) => (s.seq === seq ? { ...s, ...patch } : s));
        const next = { ...run, stops };
        if (recompute) next.status = deriveRunStatus(next);
        return next;
      })
    );
  }

  /** Re-derive a run's headline status from its stops. */
  function deriveRunStatus(run: Run): RunStatus {
    if (isRunComplete(run)) return "done";
    const anyLateOrBlocked =
      run.stops.some((s) => s.status === "late") || hasUnresolvedAbsent(run);
    const anyMovement = run.stops.some((s) => s.status !== "pending");
    if (anyLateOrBlocked) return "delayed";
    if (anyMovement) return "delivering";
    return "waiting";
  }

  function markDone(runId: string, seq: number) {
    const now = fromMinutes(currentClockMin());
    updateStop(runId, seq, { status: "done", actualAt: now });
    // advance: the next pending stop becomes enroute
    setRuns((prev) =>
      prev.map((run) => {
        if (run.id !== runId) return run;
        const cur = currentStopSeq(run);
        const stops = run.stops.map((s) => {
          if (s.seq === cur && s.status === "pending") return { ...s, status: "enroute" as StopStatus };
          return s;
        });
        const next = { ...run, stops };
        next.status = deriveRunStatus(next);
        return next;
      })
    );
    setAnnounce(`お届け先を完了として記録しました（${runId} ストップ${seq}）。`);
  }

  function markAbsent(runId: string, seq: number) {
    const now = fromMinutes(currentClockMin());
    updateStop(runId, seq, { status: "absent", actualAt: now });
    setAnnounce(`お届け先を不在として記録しました。再配達の設定が必要です（${runId} ストップ${seq}）。`);
    setRescheduleStop({ runId, seq });
    setRescheduleSlot(REDELIVERY_SLOTS[0].value);
  }

  function confirmReschedule() {
    if (!rescheduleStop) return;
    const { runId, seq } = rescheduleStop;
    const label = redeliveryLabel(rescheduleSlot);
    updateStop(runId, seq, {
      status: "done",
      rescheduledTo: label,
      note: `再配達: ${label}`,
    });
    setAnnounce(`再配達を設定しました（${runId} ストップ${seq} → ${label}）。`);
    setRescheduleStop(null);
  }

  const rescheduleTarget =
    rescheduleStop != null
      ? runs.find((r) => r.id === rescheduleStop.runId)?.stops.find((s) => s.seq === rescheduleStop.seq) ??
        null
      : null;

  const detailRun = detailRunId ? runs.find((r) => r.id === detailRunId) ?? null : null;

  /* ── render ── */

  return (
    <main className="mx-auto flex w-full max-w-6xl flex-col gap-6 p-4 sm:p-6">
      {/* polite status announcements (status changes) */}
      <div className="sr-only" role="status" aria-live="polite">
        {announce}
      </div>

      {/* 運行ヘッダ / サマリ */}
      <header className="flex flex-col gap-3">
        <div className="flex flex-col gap-1">
          <h1 className="flex items-center gap-2 text-2xl font-bold tracking-tight">
            <IconRoute className="h-6 w-6 text-primary" aria-hidden="true" />
            配送追跡 / 運行管理
          </h1>
          <p className="flex flex-wrap items-center gap-x-4 gap-y-1 text-sm text-muted-foreground">
            <span className="inline-flex items-center gap-1.5">
              <IconCalendarEvent className="h-4 w-4" aria-hidden="true" />
              配送日 {CENTER.date}
            </span>
            <span className="inline-flex items-center gap-1.5">
              <IconBuildingWarehouse className="h-4 w-4" aria-hidden="true" />
              {CENTER.center}
            </span>
          </p>
        </div>

        {/* KPIs */}
        <section aria-label="運行サマリ" className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-6">
          <Statistic label="稼働便数" value={kpis.activeRuns} hint={`全${runs.length}便`} />
          <Statistic
            label="配送中"
            value={kpis.delivering}
            change={`完了 ${kpis.doneRuns}便`}
            trend="flat"
          />
          <Statistic label="完了便" value={kpis.doneRuns} tone="positive" />
          <Statistic
            label="遅延便数"
            value={kpis.delayedRuns}
            tone={kpis.delayedRuns > 0 ? "negative" : "neutral"}
            change={kpis.delayedRuns > 0 ? "要対応" : "なし"}
            trend={kpis.delayedRuns > 0 ? "down" : "flat"}
          />
          <Statistic
            label="不在件数"
            value={kpis.absentStops}
            tone={kpis.absentStops > 0 ? "negative" : "neutral"}
            change={kpis.absentStops > 0 ? "再配達待ち" : "なし"}
            trend={kpis.absentStops > 0 ? "down" : "flat"}
          />
          <Statistic
            label="全体進捗"
            value={`${kpis.progressPct}%`}
            hint={`完了 ${kpis.doneStops}/${kpis.totalStops} 件`}
          />
        </section>
        <Progress
          value={kpis.doneStops}
          max={kpis.totalStops}
          tone={kpis.progressPct === 100 ? "success" : "primary"}
          label="全体配送進捗"
          valueText={`完了 ${kpis.doneStops}/${kpis.totalStops} 件（${kpis.progressPct}%）`}
          className="h-2.5"
        />
      </header>

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-[minmax(0,22rem)_minmax(0,1fr)]">
        {/* ───────────── 便一覧 ───────────── */}
        <section aria-label="便一覧" className="flex flex-col gap-3">
          <div className="flex items-center justify-between gap-2">
            <h2 className="text-base font-semibold">便一覧</h2>
            <Tabs value={filter} onValueChange={(v) => setFilter(v as BoardFilter)}>
              <TabsList aria-label="便の絞り込み">
                <TabsTrigger value="all">全便</TabsTrigger>
                <TabsTrigger value="delivering">配送中</TabsTrigger>
                <TabsTrigger value="delayed">遅延</TabsTrigger>
                <TabsTrigger value="done">完了</TabsTrigger>
              </TabsList>
            </Tabs>
          </div>

          {filteredRuns.length === 0 ? (
            <Card>
              <CardContent className="py-8">
                <EmptyState
                  icon={<IconTruckDelivery aria-hidden="true" />}
                  title="該当する便がありません"
                  description="この絞り込み条件に一致する稼働便はありません。"
                  headingLevel={3}
                />
              </CardContent>
            </Card>
          ) : (
            <ul className="flex flex-col gap-3" role="list">
              {filteredRuns.map((run) => {
                const p = runProgress(run);
                const selected = run.id === selectedRun?.id;
                const eta = nextEta(run);
                const meterTone: MeterTone =
                  run.status === "done" ? "success" : run.status === "delayed" ? "warning" : "primary";
                return (
                  <li key={run.id}>
                    <button
                      type="button"
                      onClick={() => setSelectedId(run.id)}
                      aria-pressed={selected}
                      aria-label={`${run.name} ${run.route} ${RUN_STATUS_LABEL[run.status]} 進捗 ${p.done}/${p.total}件`}
                      className={`w-full rounded-lg border bg-card p-3 text-left text-card-foreground shadow-sm transition-colors hover:bg-muted/60 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring ${
                        selected ? "border-primary ring-1 ring-primary" : "border-border"
                      }`}
                    >
                      <div className="flex items-start justify-between gap-2">
                        <div className="min-w-0">
                          <div className="flex items-center gap-2">
                            <span className="font-semibold">{run.name}</span>
                            <Badge variant={RUN_BADGE_VARIANT[run.status]} className="gap-1">
                              <RunStatusIcon status={run.status} />
                              {RUN_STATUS_LABEL[run.status]}
                            </Badge>
                          </div>
                          <p className="mt-0.5 truncate text-xs text-muted-foreground">{run.route}</p>
                        </div>
                        <IconChevronRight
                          className="mt-0.5 h-4 w-4 shrink-0 text-muted-foreground"
                          aria-hidden="true"
                        />
                      </div>

                      <dl className="mt-2 flex flex-wrap items-center gap-x-3 gap-y-0.5 text-xs text-muted-foreground">
                        <div className="inline-flex items-center gap-1">
                          <IconUser className="h-3.5 w-3.5" aria-hidden="true" />
                          <dt className="sr-only">ドライバー</dt>
                          <dd>{run.driver}</dd>
                        </div>
                        <div className="inline-flex items-center gap-1">
                          <IconCar className="h-3.5 w-3.5" aria-hidden="true" />
                          <dt className="sr-only">車両</dt>
                          <dd className="tabular-nums">{run.vehicle}</dd>
                        </div>
                      </dl>

                      <div className="mt-2">
                        <Meter
                          value={p.done}
                          max={p.total}
                          tone={meterTone}
                          size="inline"
                          label={`${run.name} 配送進捗`}
                          valueText={`完了 ${p.done}/${p.total} 件（${p.pct}%）`}
                        />
                      </div>

                      <div className="mt-2 flex items-center justify-between text-xs">
                        <span className="tabular-nums text-muted-foreground">
                          {p.done}/{p.total} 件 完了
                        </span>
                        {eta ? (
                          <span className="inline-flex items-center gap-1 text-foreground">
                            <IconClock className="h-3.5 w-3.5" aria-hidden="true" />
                            次の到着予定 {eta}
                          </span>
                        ) : (
                          <span className="inline-flex items-center gap-1 text-success-strong">
                            <IconCircleCheck className="h-3.5 w-3.5" aria-hidden="true" />
                            全配送完了
                          </span>
                        )}
                      </div>
                    </button>
                  </li>
                );
              })}
            </ul>
          )}
        </section>

        {/* ───────────── 配送ストップの追跡 ───────────── */}
        <section aria-label="配送ストップの追跡" className="min-w-0">
          {selectedRun ? (
            <RunDetail
              run={selectedRun}
              onMarkDone={markDone}
              onMarkAbsent={markAbsent}
              onOpenDetail={() => setDetailRunId(selectedRun.id)}
              onReschedule={(seq) => {
                setRescheduleStop({ runId: selectedRun.id, seq });
                setRescheduleSlot(REDELIVERY_SLOTS[0].value);
              }}
            />
          ) : (
            <Card>
              <CardContent className="py-10">
                <EmptyState
                  icon={<IconRoute aria-hidden="true" />}
                  title="稼働中の便がありません"
                  description="本日の運行が登録されると、ここに便と配送ストップが表示されます。"
                />
              </CardContent>
            </Card>
          )}
        </section>
      </div>

      {/* ───────────── 再配達設定 Sheet ───────────── */}
      <Sheet
        open={rescheduleStop != null}
        onOpenChange={(o) => {
          if (!o) setRescheduleStop(null);
        }}
      >
        <SheetContent side="right" className="flex w-full flex-col gap-4 sm:max-w-md">
          <SheetHeader>
            <SheetTitle>再配達日時を設定</SheetTitle>
            <SheetDescription>
              {rescheduleTarget
                ? `${rescheduleTarget.customer} 様（${rescheduleTarget.parcels}個）への再配達を登録します。`
                : "再配達を登録します。"}
            </SheetDescription>
          </SheetHeader>

          {rescheduleTarget ? (
            <div className="flex flex-col gap-4">
              <Alert variant="destructive">
                <IconHomeExclamation className="h-4 w-4" aria-hidden="true" />
                <AlertTitle as="h3">不在のため未配達</AlertTitle>
                <AlertDescription>
                  {rescheduleTarget.address}
                  <br />
                  予定 {rescheduleTarget.plannedEta}
                  {rescheduleTarget.actualAt ? ` / 訪問 ${rescheduleTarget.actualAt}` : ""}・不在票投函
                </AlertDescription>
              </Alert>

              <Select
                label="再配達 希望日時"
                value={rescheduleSlot}
                onChange={(e) => setRescheduleSlot(e.target.value)}
              >
                {REDELIVERY_SLOTS.map((s) => (
                  <option key={s.value} value={s.value}>
                    {s.label}
                  </option>
                ))}
              </Select>

              <div className="flex items-center gap-2">
                <Button type="button" variant="success" onClick={confirmReschedule}>
                  <IconCalendarClock className="h-4 w-4" aria-hidden="true" />
                  再配達を確定
                </Button>
                <Button type="button" variant="outline" onClick={() => setRescheduleStop(null)}>
                  キャンセル
                </Button>
              </div>
            </div>
          ) : null}
        </SheetContent>
      </Sheet>

      {/* ───────────── 運行詳細 / 遅延連絡 Sheet ───────────── */}
      <Sheet
        open={detailRunId != null}
        onOpenChange={(o) => {
          if (!o) setDetailRunId(null);
        }}
      >
        <SheetContent side="right" className="flex w-full flex-col gap-4 overflow-y-auto sm:max-w-md">
          {detailRun ? (
            <RunDetailSheet
              run={detailRun}
              onContacted={() =>
                setAnnounce(`${detailRun.name} のお客様へ遅延連絡を記録しました。`)
              }
            />
          ) : null}
        </SheetContent>
      </Sheet>
    </main>
  );
}

/* ───────────────────────── run detail (the centerpiece) ───────────────────────── */

function RunDetail({
  run,
  onMarkDone,
  onMarkAbsent,
  onOpenDetail,
  onReschedule,
}: {
  run: Run;
  onMarkDone: (runId: string, seq: number) => void;
  onMarkAbsent: (runId: string, seq: number) => void;
  onOpenDetail: () => void;
  onReschedule: (seq: number) => void;
}) {
  const p = runProgress(run);
  const curSeq = currentStopSeq(run);
  const complete = isRunComplete(run);
  const blocking = hasUnresolvedAbsent(run);
  const meterTone: MeterTone = complete ? "success" : run.status === "delayed" ? "warning" : "primary";

  return (
    <Card>
      <CardHeader className="gap-3">
        <div className="flex flex-col gap-2 sm:flex-row sm:items-start sm:justify-between">
          <div className="min-w-0">
            <CardTitle as="h2" className="flex flex-wrap items-center gap-2 text-lg">
              {run.name}
              <Badge variant={RUN_BADGE_VARIANT[run.status]} className="gap-1">
                <RunStatusIcon status={run.status} />
                {RUN_STATUS_LABEL[run.status]}
              </Badge>
            </CardTitle>
            <CardDescription className="mt-1 flex flex-wrap items-center gap-x-3 gap-y-1">
              <span className="inline-flex items-center gap-1">
                <IconMapPin className="h-3.5 w-3.5" aria-hidden="true" />
                {run.route}
              </span>
              <span className="inline-flex items-center gap-1">
                <IconUser className="h-3.5 w-3.5" aria-hidden="true" />
                {run.driver}
              </span>
              <span className="inline-flex items-center gap-1 tabular-nums">
                <IconCar className="h-3.5 w-3.5" aria-hidden="true" />
                {run.vehicle}
              </span>
            </CardDescription>
          </div>
          <Button type="button" variant="outline" size="sm" onClick={onOpenDetail} className="shrink-0">
            運行詳細
            <IconArrowRight className="h-4 w-4" aria-hidden="true" />
          </Button>
        </div>

        <Meter
          value={p.done}
          max={p.total}
          tone={meterTone}
          label="配送進捗"
          valueText={`完了 ${p.done}/${p.total} 件（${p.pct}%）`}
          showValue
        />
      </CardHeader>

      <CardContent className="flex flex-col gap-4">
        {/* 例外: 遅延 / 不在 announcement */}
        <div aria-live="assertive">
          {run.status === "delayed" && run.delay ? (
            <Alert variant="warning">
              <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h3">
                遅延中 — 約{run.delay.minutes}分の遅れ（{DELAY_REASON_LABEL[run.delay.reason]}）
              </AlertTitle>
              <AlertDescription>
                残りのお届け先の到着予定が後ろ倒しになっています。お客様へ遅延連絡を行ってください。
                <div className="mt-2">
                  <Button type="button" variant="warning" size="sm" onClick={onOpenDetail}>
                    <IconPhone className="h-4 w-4" aria-hidden="true" />
                    お客様へ連絡
                  </Button>
                </div>
              </AlertDescription>
            </Alert>
          ) : blocking ? (
            <Alert variant="destructive">
              <IconHomeExclamation className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h3">不在のお届け先があります</AlertTitle>
              <AlertDescription>
                再配達を設定するまでこの便は完了になりません。下のストップから再配達を設定してください。
              </AlertDescription>
            </Alert>
          ) : complete ? (
            <Alert variant="success">
              <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h3">この便はすべて配送完了しました</AlertTitle>
              <AlertDescription>
                全{p.total}件のお届けが完了しています。運行を終了できます。
              </AlertDescription>
            </Alert>
          ) : null}
        </div>

        {/* the ordered stop list / route timeline */}
        <div>
          <div className="mb-2 flex items-center justify-between">
            <h3 className="text-sm font-semibold">配送ストップ</h3>
            <span className="text-xs text-muted-foreground">
              完了は上、未配は下・現在地は強調表示
            </span>
          </div>

          <Timeline aria-label={`${run.name} の配送ルート`}>
            {run.stops.map((stop, i) => {
              const isCurrent = stop.seq === curSeq;
              const isLast = i === run.stops.length - 1;
              return (
                <TimelineItem
                  key={stop.seq}
                  connector={!isLast}
                  variant={STOP_TIMELINE_VARIANT[stop.status]}
                  marker={
                    <span
                      aria-hidden="true"
                      className={`flex h-4 w-4 items-center justify-center rounded-full ${
                        stop.status === "done"
                          ? "bg-success-strong text-success-strong-foreground"
                          : stop.status === "absent"
                            ? "bg-destructive-strong text-destructive-strong-foreground"
                            : stop.status === "late"
                              ? "bg-warning-strong text-warning-strong-foreground"
                              : isCurrent
                                ? "bg-primary text-primary-foreground ring-2 ring-primary/40"
                                : "border-2 border-muted-foreground/40 bg-background text-muted-foreground"
                      }`}
                    >
                      <StopStatusIcon status={stop.status} className="h-3 w-3" />
                    </span>
                  }
                  aria-current={isCurrent ? "step" : undefined}
                  className={
                    isCurrent
                      ? "rounded-lg bg-primary/5 ring-1 ring-primary/30"
                      : undefined
                  }
                >
                  <div className={isCurrent ? "px-2 py-1.5" : ""}>
                    {/* row head: seq + customer + status */}
                    <div className="flex flex-wrap items-center gap-x-2 gap-y-1">
                      <span className="inline-flex h-5 min-w-[1.5rem] items-center justify-center rounded bg-muted px-1.5 text-xs font-bold tabular-nums">
                        {stop.seq}
                      </span>
                      <span className="font-semibold">{stop.customer}</span>
                      <StopStatusBadge status={stop.status} />
                      {isCurrent ? (
                        <Badge variant="info" className="gap-1">
                          <IconMapPin className="h-3 w-3" aria-hidden="true" />
                          現在地
                        </Badge>
                      ) : null}
                    </div>

                    {/* address + parcels */}
                    <p className="mt-1 flex items-start gap-1 text-sm text-muted-foreground">
                      <IconMapPin className="mt-0.5 h-3.5 w-3.5 shrink-0" aria-hidden="true" />
                      <span className="min-w-0">{stop.address}</span>
                    </p>
                    <p className="mt-0.5 inline-flex items-center gap-1 text-xs text-muted-foreground">
                      <IconPackage className="h-3.5 w-3.5" aria-hidden="true" />
                      {stop.parcels}個
                    </p>

                    {/* planned ETA vs actual + delay */}
                    <div className="mt-2 flex flex-wrap items-center gap-x-4 gap-y-1 text-xs">
                      <span className="inline-flex items-center gap-1 text-muted-foreground">
                        <IconClock className="h-3.5 w-3.5" aria-hidden="true" />
                        予定
                        <span className="font-semibold tabular-nums text-foreground">
                          {stop.plannedEta}
                        </span>
                      </span>
                      <span className="inline-flex items-center gap-1 text-muted-foreground">
                        実績
                        <span className="font-semibold tabular-nums text-foreground">
                          {stop.actualAt ?? "—"}
                        </span>
                      </span>
                      <StopDelta stop={stop} />
                    </div>

                    {stop.rescheduledTo ? (
                      <p className="mt-1.5 inline-flex items-center gap-1 rounded bg-info-subtle px-2 py-0.5 text-xs text-info-subtle-foreground">
                        <IconCalendarClock className="h-3.5 w-3.5" aria-hidden="true" />
                        再配達: {stop.rescheduledTo}
                      </p>
                    ) : null}

                    {/* per-stop actions */}
                    <StopActions
                      stop={stop}
                      onMarkDone={() => onMarkDone(run.id, stop.seq)}
                      onMarkAbsent={() => onMarkAbsent(run.id, stop.seq)}
                      onReschedule={() => onReschedule(stop.seq)}
                    />
                  </div>
                </TimelineItem>
              );
            })}
          </Timeline>
        </div>
      </CardContent>
    </Card>
  );
}

function StopActions({
  stop,
  onMarkDone,
  onMarkAbsent,
  onReschedule,
}: {
  stop: DeliveryStop;
  onMarkDone: () => void;
  onMarkAbsent: () => void;
  onReschedule: () => void;
}) {
  const actionable = stop.status === "enroute" || stop.status === "late" || stop.status === "pending";
  const needsReschedule = isStopBlocking(stop);

  if (!actionable && !needsReschedule) return null;

  return (
    <div className="mt-2.5 flex flex-wrap items-center gap-2">
      {actionable ? (
        <>
          <Button
            type="button"
            size="sm"
            variant="success"
            onClick={onMarkDone}
            aria-label={`${stop.customer} を完了にする`}
          >
            <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
            完了にする
          </Button>
          <Button
            type="button"
            size="sm"
            variant="outline"
            onClick={onMarkAbsent}
            aria-label={`${stop.customer} を不在として登録`}
          >
            <IconHomeExclamation className="h-4 w-4" aria-hidden="true" />
            不在登録
          </Button>
        </>
      ) : null}
      {needsReschedule ? (
        <Button
          type="button"
          size="sm"
          variant="destructive"
          onClick={onReschedule}
          aria-label={`${stop.customer} の再配達を設定`}
        >
          <IconCalendarClock className="h-4 w-4" aria-hidden="true" />
          再配達を設定
        </Button>
      ) : null}
    </div>
  );
}

/* ───────────────────────── 運行詳細 / 遅延連絡 sheet ───────────────────────── */

function RunDetailSheet({ run, onContacted }: { run: Run; onContacted: () => void }) {
  const p = runProgress(run);
  const [reason, setReason] = React.useState<string>(run.delay?.reason ?? "traffic");
  const [contacted, setContacted] = React.useState(false);

  return (
    <>
      <SheetHeader>
        <SheetTitle>運行詳細 — {run.name}</SheetTitle>
        <SheetDescription>{run.route}</SheetDescription>
      </SheetHeader>

      <dl className="grid grid-cols-2 gap-x-4 gap-y-3 text-sm">
        <div>
          <dt className="text-xs text-muted-foreground">ドライバー</dt>
          <dd className="font-medium">{run.driver}</dd>
        </div>
        <div>
          <dt className="text-xs text-muted-foreground">車両</dt>
          <dd className="font-medium tabular-nums">{run.vehicle}</dd>
        </div>
        <div>
          <dt className="text-xs text-muted-foreground">ステータス</dt>
          <dd>
            <Badge variant={RUN_BADGE_VARIANT[run.status]} className="gap-1">
              <RunStatusIcon status={run.status} />
              {RUN_STATUS_LABEL[run.status]}
            </Badge>
          </dd>
        </div>
        <div>
          <dt className="text-xs text-muted-foreground">進捗</dt>
          <dd className="font-medium tabular-nums">
            {p.done}/{p.total} 件（{p.pct}%）
          </dd>
        </div>
      </dl>

      <Separator />

      <div className="flex flex-col gap-3">
        <h3 className="text-sm font-semibold">遅延・例外処理</h3>
        <Select
          label="遅延理由"
          value={reason}
          onChange={(e) => setReason(e.target.value)}
        >
          {DELAY_REASON_OPTIONS.map((o) => (
            <option key={o.value} value={o.value}>
              {o.label}
            </option>
          ))}
        </Select>

        <div aria-live="polite">
          {contacted ? (
            <Alert variant="success">
              <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h4">連絡済み</AlertTitle>
              <AlertDescription>
                {DELAY_REASON_LABEL[reason as keyof typeof DELAY_REASON_LABEL]} を理由に、お客様へ遅延連絡を記録しました。
              </AlertDescription>
            </Alert>
          ) : null}
        </div>

        <div className="flex items-center gap-2">
          <Button
            type="button"
            variant="warning"
            onClick={() => {
              setContacted(true);
              onContacted();
            }}
          >
            <IconPhone className="h-4 w-4" aria-hidden="true" />
            お客様へ遅延連絡
          </Button>
        </div>
      </div>
    </>
  );
}

/* ───────────────────────── clock ───────────────────────── */

/**
 * Deterministic "now" for the demo so SSR/CSR match (no hydration drift) and the
 * recorded actual times stay sensible against the seed ETAs. Returns minutes
 * since midnight; advances slightly per mutation so successive marks differ.
 */
function currentClockMin(): number {
  const base = toMinutes("10:18");
  return base + mutationSeq++;
}
